external_knowledge:
- 'styles' refers to the product type (e.g., tops, bottoms, dresses);
- 'various styles and genders' means product_type and gender;
- 'broken down by region' indicates the data is categorized by region;
- 'how [they] were accessed' refers to the total number of access occurrences for each size chart.

sql:
SELECT products.product_name, users.user_name
FROM products, users
WHERE products.product_id = 0 AND users.user_id = 1;

SELECT COUNT(*) AS TotalEssentialMeasurements
FROM measurements
WHERE is_required = 1;

SELECT region, AVG(local_size) AS average_local_size
FROM size_conversions
GROUP BY region;
